from collections import deque

class Solution(object):
    def countOfPairs(self, n, x, y):
        # Build graph: 1-indexed, linear chain + shortcut edge x-y
        adj = [[] for _ in range(n + 1)]
        for i in range(1, n):
            adj[i].append(i + 1)
            adj[i + 1].append(i)
        if x != y:
            adj[x].append(y)
            adj[y].append(x)
        result = [0] * (n + 1)
        for start in range(1, n + 1):
            dist = [-1] * (n + 1)
            dist[start] = 0
            q = deque([start])
            while q:
                u = q.popleft()
                for v in adj[u]:
                    if dist[v] == -1:
                        dist[v] = dist[u] + 1
                        q.append(v)
            for end in range(1, n + 1):
                if end != start and dist[end] > 0:
                    result[dist[end]] += 1
        return result[1:]
